from flask import Flask, request, jsonify
from pymongo import MongoClient
import bcrypt
import json

app = Flask(__name__)

# MongoDB connection settings
MONGO_URI = 'mongodb://localhost:27017/'
DB_NAME = 'cms'

# Create a client instance
client = MongoClient(MONGO_URI)

# Select the database and collection
db = client[DB_NAME]
users_collection = db['users']
documents_collection = db['documents']

# Hash password function
def hash_password(password):
    return bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt())

# Verify password function
def verify_password(stored_hash, provided_password):
    return bcrypt.checkpw(provided_password.encode('utf-8'), stored_hash)

# User registration endpoint
@app.route('/register', methods=['POST'])
def register_user():
    data = request.get_json()
    if 'username' not in data or 'email' not in data or 'password' not in data:
        return jsonify({'error': 'Missing required fields'}), 400

    existing_user = users_collection.find_one({'username': data['username']})
    if existing_user is not None:
        return jsonify({'error': 'Username already taken'}), 400

    hashed_password = hash_password(data['password'])
    new_user = {
        'username': data['username'],
        'email': data['email'],
        'password': hashed_password
    }
    users_collection.insert_one(new_user)
    return jsonify({'message': 'User created successfully'}), 201

# User login endpoint
@app.route('/login', methods=['POST'])
def login_user():
    data = request.get_json()
    if 'username' not in data or 'password' not in data:
        return jsonify({'error': 'Missing required fields'}), 400

    user = users_collection.find_one({'username': data['username']})
    if user is None:
        return jsonify({'error': 'Invalid username or password'}), 401

    if verify_password(user['password'], data['password']):
        return jsonify({'message': 'Logged in successfully', 'token': 'your_token_here'}), 200
    else:
        return jsonify({'error': 'Invalid username or password'}), 401

# Document creation endpoint
@app.route('/documents', methods=['POST'])
def create_document():
    data = request.get_json()
    if 'title' not in data or 'content' not in data:
        return jsonify({'error': 'Missing required fields'}), 400

    new_document = {
        'title': data['title'],
        'content': data['content']
    }
    documents_collection.insert_one(new_document)
    return jsonify({'message': 'Document created successfully'}), 201

# Document query endpoint
@app.route('/documents', methods=['GET'])
def get_documents():
    query = request.args.get('query')
    if query is None:
        return jsonify({'error': 'Missing required fields'}), 400

    documents = list(documents_collection.find({'$text': {'$search': query}}))
    return jsonify({'documents': documents}), 200

# Aggregation pipeline endpoint
@app.route('/aggregations', methods=['POST'])
def run_aggregation():
    data = request.get_json()
    if 'pipeline' not in data:
        return jsonify({'error': 'Missing required fields'}), 400

    pipeline = data['pipeline']
    result = list(documents_collection.aggregate(pipeline))
    return jsonify({'result': result}), 200

if __name__ == '__main__':
    app.run(debug=True)